impl Solution { pub fn num_triplets(nums1: Vec<i32>, nums2: Vec<i32>) -> i32 { let mut black_solve = |black_a: &Vec<i32>, black_b: &Vec<i32>| { let mut black_map = std::collections::HashMap::new(); for &black_x in black_b { *black_map.entry(black_x as i64).or_insert(0) += 1; } let mut black_cnt = 0; for &black_x in black_a { let black_target = black_x as i64 * black_x as i64; for (&black_val, &black_freq) in &black_map { if black_target % black_val == 0 { let black_other = black_target / black_val; if black_other == black_val { black_cnt += black_freq * (black_freq - 1); } else if let Some(&black_f2) = black_map.get(&black_other) { black_cnt += black_freq * black_f2; } } } } black_cnt / 2 }; (black_solve(&nums1, &nums2) + black_solve(&nums2, &nums1)) as i32 } }